import{_ as i,a,b as g,c as e,d as t,e as n,f as p,g as s,h as r,i as o,j as c,k as m,l as f}from"./image-20240123223643418-87e15607.js";import{_ as d}from"./plugin-vue_export-helper-c27b6911.js";import{o as l,c as _,e as u}from"./app-405c8987.js";const b="/assets/image-20240121164001826-a3d92957.png",h="/assets/image-20240121164311131-353b8dd5.png",x="/assets/image-20240121164347527-1693575c.png",y="/assets/image-20240121164507282-f64c07eb.png",z="/assets/image-20240121164548594-f1ef2339.png",$="/assets/image-20240121164846224-aa90d74e.png",k="/assets/image-20240121165144109-dc9b06c1.png",B="/assets/image-20240121165214409-b0403074.png",C="/assets/image-20240121165253890-4db71a2f.png",A="/assets/image-20240123203628929-e0059052.png",E="/assets/image-20240123203859120-87429b12.png",q="/assets/image-20240123204218583-a50866f3.png",v="/assets/image-20240123204246863-aeff501c.png",D="/assets/image-20240123204333018-feb4ec29.png",V="/assets/image-20240123204608779-7a21b62a.png",j="/assets/image-20240123210305955-ddf0445a.png",N="/assets/image-20240123210433037-6437a38d.png",S="/assets/image-20240123210528121-d8b73209.png",w="/assets/image-20240123211253671-85be3c8a.png",F="/assets/image-20240123211322439-f3a06620.png",G="/assets/image-20240123211423378-29d71c62.png",H="/assets/image-20240123211749155-7a97bd02.png",I="/assets/image-20240123211800325-bd5c371d.png",J="/assets/image-20240123213135915-f90d3f53.png",K="/assets/image-20240123213213051-65a1183f.png",L="/assets/image-20240123213235253-2e91a163.png",M="/assets/image-20240123213410723-fce51a17.png",O="/assets/image-20240123220442399-4a0ec0c9.png",P="/assets/image-20240123220830642-46561892.png",Q="/assets/image-20240123220946804-44334405.png",R="/assets/image-20240123221012791-f33f9cc1.png",T="/assets/image-20240123221248277-658d9b8c.png",U="/assets/image-20240123222633328-be432240.png",W="/assets/image-20240123222717769-468472f3.png",X="/assets/image-20240123222744272-dbade824.png",Y="/assets/image-20240123223056510-db04cea0.png",Z="/assets/image-20240123223145334-6ec0b8a5.png",i2={},a2=u('<h1 id="其它反转形态" tabindex="-1"><a class="header-anchor" href="#其它反转形态" aria-hidden="true">#</a> 其它反转形态</h1><p>比较而言，我们在第四章和第五章所介绍的反转形态都是较强的反转信号。一旦它们出现，就表明牛方已经从熊方手中夺过了大权（比如说看涨吞没形态、启明星形态，或者刺透形态等），或者熊方已经从牛方手中抢回了主动权（比如说看跌吞没形态，黄昏星形态或者乌云盖顶形态等）。本章要讨论更多的反转形态。其中一部分形态通常一但并不总是一一构成反转信号，因此，它们是较弱的反转信号。这些形态包括孕线形态、平头顶部形态和平头底部形态、捉腰带蜡烛线、向上跳空二只乌鸦、反击蜡烛线等。然后本章还要探讨一些强烈的反转信号，其中包括三只乌鸦、三山形态、三川形态，圆形顶、圆顶底、塔形顶和塔形底等。</p><h2 id="孕线形态" tabindex="-1"><a class="header-anchor" href="#孕线形态" aria-hidden="true">#</a> 孕线形态</h2><figure><img src="'+i+'" alt="image-20240119233945566" tabindex="0" loading="lazy"><figcaption>image-20240119233945566</figcaption></figure><p>如图6.1所示即孕线形态，<strong>其中后一根蜡烛线的实体较小，并且被前一根相对较长的实体包容进去</strong>。本形态的名字来自一个古老的日本名词，意思就是“怀孕”。在本形态中，长的蜡烛线是“母”蜡烛线，而小的蜡烛线则是“子”或“胎”蜡烛线。在第三章，我们曾交代过，纺锤线（即具有小实体的蜡烛线）在某些形态中很有用处。孕线形态就是这些形态的一个例子（星线也是一个例子，这在第五章已有探讨）。</p><p>孕线形态与吞没形态相比，两根蜡烛线的顺序恰好颠倒过来。在吞没形态中，后面是一根长长的实体，它将前一个小实体覆盖进去了。而在孕线形态中，前一个是非常长的实体，它将后一个小实体包容起来。在吞没形态中，两根蜡烛线的实体的颜色应当互不相同。而在孕线形态中，这一点倒不是一项必要条件。无论如何，最终您会发现，在绝大多数情况下，孕线形态的两个实体的颜色也是不同的。图6.7显示了吞没形态与孕线形态之间的区别。</p><p>孕线形态与西方技术分析理论中的收缩日概念有相似之处。按照西方的理论，如果某日最高价和最低价均居于前一日价格区间的内部，则这一天就是一个收缩日（如图6.2所示）。但是，西方技术分析理论认为，收缩日通常没有什么预测意义。<strong>而在蜡烛图理论中，孕线形态的出现，预示着市场将同先前的趋势分道扬镳。<strong>另一方面，西方的收缩日概念仅要求当日的最高点和最低点都处在前一时间段的区间之内，而</strong>孕线形态则不仅要求当日的开市价与收市价均处于前一日的较宽的开市价与收市价的范围之内（即前一日是一个较高的实体），而且要求当日的开市价与收市价之间的距离比较小（即这一天是一根较小的实体）</strong>。</p><p>与其它一些反转形态相比，比如说锤子线、上吊线或吞没形态等，孕线形态所构成的反转信号通常不如它们重要。<strong>当孕线形态出现时</strong>，好象市场的刹车踏板被踩了下去，于是<strong>当前的市场趋势就结束了</strong>。然后，市场常常<strong>转入平静状态</strong>。有的时候，孕线形态也可能构成重大趋势变化的警告信号---尤其是在它处于市场顶部的情况下。</p><figure><img src="'+a+'" alt="image-20240121163635453" tabindex="0" loading="lazy"><figcaption>image-20240121163635453</figcaption></figure><p>图6.3所示的是一类特别的孕线形态，称为十字孕线形态。所谓十字孕线形态，指的是在孕线形态中，第二天是一根十字线，而不是一个小实体。因为十字孕线形态包含了一根强有力的十字蜡烛线（第八章将更详尽地讨论十字线），所以这类形态被视为主要反转信号。十字孕线形态有时也称为呆滞形态。</p><p>如图6.1所示，在孕线形态中，第二根蜡烛线的颜色是无所谓的。这种形态的决定性特征是。第二个时间单位的实体相对于第一个时间单位的实体是非常小的，并且这个小实体居于大实体内部。无论在一般的孕线形态中，还是在十字孕线形态中，上下影线的大小通常是无关紧要的。</p><p>孕线形态揭示了市场在其前后健康状况的明显反差。在牛市行情中，孕线形态的前一个长长的白色实体表明，市场本来充满了活力，但是，后一个小小的实体却反映出市场犹疑不定。这说明牛方向上的推动力正在衰退。由此看来，有可能发生趋势反转。在熊市行情中，孕线形态的前一根长长的黑色蜡烛线反映了沉重的抛售压力，但是，随后的小实体却表明市场踌躇不前。第二天的小实体是个警告信号。说明熊方的力量正在减弱，因此，本形态可能构成趋势反转信号。</p><figure><img src="'+b+'" alt="image-20240121164001826" tabindex="0" loading="lazy"><figcaption>image-20240121164001826</figcaption></figure><p>如图6.4所示，从4月18日开始，有一段小规棋的上涨行情。孕线形态1结束了这段行情。从孕线形态1开始，市场形成了一轮抛售行情，孕线形态2又阻止了这轮下跌过程。孕线形态3表明，即使在孕线形态出现前市场并无明显的趋势，孕线形态也可能具有一定的参考价值。请注意，5月的头几天，市场并无明显的趋势可循。就在这个时候，孕线形态3出现了。它的第一天是一根长长的白色实体，第二天是一根小小的黑色实体（请记住，第二天实体的颜色是无关宏旨的）。</p><p>根据这个形态发出的信号，交易商依然可以得出这样的判断：由第一天坚挺的白色实体所代表的上涨行情已经归于失败。此时此刻，市场正处在上下两难的状态下。当市场收市于孕线形态3的高点以上时，才从这种犹疑状态中解脱出来；只有在市场解脱出来之后，我们才能做出买进的建议。</p><p>孕线形态4是一个经典的实例。在本形态的高高的白色实体之前，市场呈现出明显的上升趋势。当次日的小实体形成后，这个孕线形态就完成了。此外，这个小实体还具有另一方面的疲弱意义：这是一根流星线（虽然它不是一个完美的星线，因为它的实体不在前一个实体的上方）。</p><figure><img src="'+h+'" alt="image-20240121164311131" tabindex="0" loading="lazy"><figcaption>image-20240121164311131</figcaption></figure><p>如图6.5所示，是两个十分典型的孕线形态实例。在这两个孕线形态中，第二日的短实体与第一日长实体相比都是微不足道的。第一个孕线形态的出现，说明市场缺乏上升的动力；第二个孕线形态的出现，意味着市场上抛售压力的桔竭。</p><figure><img src="'+x+'" alt="image-20240121164347527" tabindex="0" loading="lazy"><figcaption>image-20240121164347527</figcaption></figure><p>如图6.6所示，3月下旬出现了一个二蜡烛线的孕线形态，请看它是如何标志着市场顶部的到来的。随后形成的抛售行情一直持续到4月24日的看涨锤子线为止。请注意，在这个孕线形态中，第二天的影线已经超出了第一天实体的范围。这一实例证明，在孕线形态中，两个实体的相对大小是至关重要的，而它们的影线的相互关系，则无须深究。</p><figure><img src="'+y+'" alt="image-20240121164507282" tabindex="0" loading="lazy"><figcaption>image-20240121164507282</figcaption></figure><p>如图6.7所示，在5月7日和8日组成的看跌吞没形态之后，市场形成了一轮剧烈的下跌行情。后来，本图所示的孕线形态标志着市场从下降趋势向横向区间的转化。</p><figure><img src="'+z+'" alt="image-20240121164548594" tabindex="0" loading="lazy"><figcaption>image-20240121164548594</figcaption></figure><p>如图6.8所示，日内交易商可以利用这一孕线形态的技术信号，判断之前的日内规模的下降趋势可能已经结束了。如果据此采取怡当的交易措施，则可以获得一定的回报。在本实例中，4月17日早晨，市场经历了一段陡峭的下滑，在这个孕线形态出现后，这段跌势就此罢休，市场转入平缓的状态。日内交易者或许可以凭着这个孕线形态的信号平回空头头寸。本例的孕线形态并不排除市场再度恢复为下降趋势的可能性，这一点与任何底部反转形态都是一致的。无论如何，这个孕线形态确实揭示了当前的市场状态。具体地说，该形态告诉我们，至少在它出现的这个时刻，市场上向下的压力已经消退了。</p><figure><img src="'+$+'" alt="image-20240121164846224" tabindex="0" loading="lazy"><figcaption>image-20240121164846224</figcaption></figure><p>图6.9所示是个很好的实例，它说明在图示的孕线形态出现后，市场从急剧的下降趋势转化为水平延伸的交易区间。在这个孕线形态之前的下跌过程中，市场价格从5.40美元狂泻到4.85美元。我们看到该孕线形态如中流砥柱，堵住了这场暴跌。话说回来，孕线形态的出现未必一定预示着市场的上涨。在孕线形态出现后，市场通常缓和下来，转化为横向整理区间。</p><h2 id="十字孕线形态" tabindex="-1"><a class="header-anchor" href="#十字孕线形态" aria-hidden="true">#</a> 十字孕线形态</h2><p>在常规的孕线形态中，前一根为高高的实体，后一根为小小的实体。不过，到底什么样的蜡烛线算得上“小”实体，并无一定之规。这一点与其它许多图表分析技术一样，具有主观性。<strong>作为一条普遍的经验，在孕线形态中，第二根实体越小，则整个形态越有力量</strong>。这条经验通常都是成立的，因为第二个实体越小，市场的矛盾心态就越甚，所以，越有可能酿成趋势反转。在极端的情况下，随着第二根蜡烛线的开市价与收市价之间的距离的收窄，这个实体越来越小，最后就形成了一根十字线。</p><p>我们曾经提到，如果在一根十字线之前有一根长长的实体，则构成了十字孕线形态。十字孕线形态所蕴含的技术意义，比普通的孕线形态重要得多。<strong>一般的孕线形态并不属于主要反转形态，但是，十字孕线形态恰怡是一种主要反转形态</strong>。一旦在一根很长的白色蜡烛线之后出现了一根十字孕线，如果多头交易商对这个形态视而不见的话，他就把自己推到了危险的境地。十字孕线形态也可能引发底部过程，不过，当这类形态出现在市场顶部时更有效力。</p><figure><img src="'+k+'" alt="image-20240121165144109" tabindex="0" loading="lazy"><figcaption>image-20240121165144109</figcaption></figure><p>如图6.10所示，自3月中开始曾经有一轮上涨行情，但是当4月2日和3日形成的十字孕线形态出现后，这个上升趋势就逋然终止了。请注意上述演变过程是如何发生的。</p><figure><img src="'+B+'" alt="image-20240121165214409" tabindex="0" loading="lazy"><figcaption>image-20240121165214409</figcaption></figure><p>在图6.11中，1月中旬出现了一个巨大的向上价格跳空，它似乎在大喊：“牛市！”但是，图示的孕线形态宣布：“牛市到此结束。”</p><figure><img src="'+C+'" alt="image-20240121165253890" tabindex="0" loading="lazy"><figcaption>image-20240121165253890</figcaption></figure><p>图6.12显示，由一根不同寻常的巨大黑色蜡烛线，与它身后的一根十字线一起，组成了一个十字孕线形态。在本图中我们看到，从这个形态开始，市场从之前的下降趋势中挣脱出来。在这个十字孕线形态的十字线的后面，还有一根外形与锤子线相象的蜡烛线（这根蜡烛线成功地向下试探了市场最近形成的低点），这根蜡烛线给出了当前底部形态的进一步证据。</p><h2 id="平头顶部形态和平头底部形态" tabindex="-1"><a class="header-anchor" href="#平头顶部形态和平头底部形态" aria-hidden="true">#</a> 平头顶部形态和平头底部形态</h2><figure><img src="'+g+'" alt="image-20240121165439699" tabindex="0" loading="lazy"><figcaption>image-20240121165439699</figcaption></figure><figure><img src="'+e+'" alt="image-20240121165447367" tabindex="0" loading="lazy"><figcaption>image-20240121165447367</figcaption></figure><p><strong>平头形态是由具有几乎相同水平的最高点的两根蜡烛线组成的，或者是由具有几乎相同的最低点的二根蜡烛线组成的</strong>。之所以将这种形态称为平头形态，是因为这些蜡烛线的端点就像镊子腿一样平齐。在上升的市场中，当几根蜡烛线的最高点不相上下时，就形成了一个平头顶部形态。在下降的市场上，当几根蜡烛线的最低点基本一致时，就形成了一个平头底部形态。平头形态既可以由实体构成，也可以由影线或者十字线构成。平头形态既可以由相邻的蜡烛线组成，也可以由相隔较近的蜡烛线组成。不过，，在这种情况下，它通常不能成为一个决定性的反转形态。构成平头形态的蜡烛线也可能相距甚远，并且其中间夹着较长期的市场变化；或者在平头形态之内，同时包含着其它看跌的蜡烛图因素（在构成顶部反转信号时），或者同时包含着其它看涨的蜡烛图因素（在构成底部反转信号时）。在这样的情况下，平头形态就多了一些额外的技术分量，从图6.13到图6.18的各个示意图所揭示的就是上述概念。</p><p>如图6.13所示，在上升趋势中，先是一根长长的白色蜡烛线，后是一根十字线。这个二蜡烛线形态既是一个十字孕线形态，又是一个平头形态，因为这两根蜡烛线具有同样的最高点。综合来看，这个形态可能构成了重要的反转信号。如图6.14所示，在这个平头形态中，先是一根长长的白色蜡烛线，后是一根上吊线。下一天，如果市场开市于上吊线的实体之下，那么，把这个形态判断为一个顶部反转信号，就有了很大的胜算。只要市场的收市价不高于这个平头形态的顶部，那么这种看跌的态度就不可动摇。这个二蜡烛线的混合体也可以看做一个孕线形态。结合以上分析，这个孕线形态处于上升趋势中，构成了一个顶部反转形态。如图6.15所示，在这个平头顶部形态中，第二根蜡烛线同时又是一根看跌的流星线。尽管它不是一根真正的流星线，但是根据形成这根蜡烛线的价格变化过程，这根线本身是看跌的。在这根蜡烛线上，市场开市于最低点，然后上冲到前一天的最高价的水平，后来却收市于当日的最低点附近。另外，本形态还可以看成孕线形态。</p><p>如图6.16所示，是一个乌云盖顶形态的变体。在这个形态中，第二天的开市价高于第一天的收市价（而不是高于第一天的最高价）。黑色蜡烛线的最高点曾经触及前一天的最高点，而后市场再回落。这个形态既可以看做乌云盖顶形态，也可以看做平头顶部形态，是一个双重组合。如图6.17所示，在这里的二蜡烛线形态中，后一根为锤子线，并且它成功地向下试探了前一根长长的黑色蜡烛线的最低点。锤子线、市场对支撑水平的成功试探，两方面因素同时证明卖方已经丧失了对市场的控制。最后，这个二蜡烛线组合也可以视为孕线形态。这是将此处判断为一个重要支撑水平的第三条理由。如图6.18所示，为一个看涨刺透形态的变体，它同时还构成了一个平头底部形态。两者形成了一个有力的组合。在理想的刺透形态中，第二天的开市价低于第一天的最低点。但是在这个形态中，第二天的开市价仅低于第一天的收市价。</p><p>上面列举的各种平头形态的例子并没有把所有的可能性一网打尽。我们只选择了一些具有代表意义的实例，通过它们来说明平头顶部形态和平头底部形态应当得到其它蜡烛图指标的验证，如此便能够上升为一种很有价值的预测工具。对于希望获得<strong>长期的市场看法</strong>的朋友来说，不妨选用<strong>周蜡烛线图和月蜡烛线图</strong>进行研究，在这种情况下，由相邻的蜡烛线形成的平头顶部形态和平头底部形态可能构成重要的反转信号。这类形态甚至在没有其它蜡烛图信号相验证的条件下，也是成立的。我们不妨用下面的例子来说明其原因。**在周蜡烛线图或月蜡烛图上，如果前一个时间单位的低点在后一个时间单位内成功地经受了市场向下的试探，这个低点就可能构成重要的市场底部，引发上冲行情。**在日蜡烛线图上，类似的情况可能就不那么重要了，因为今天成功地经受试探的不过是昨天的低点，演变成市场底部、引发上冲行情的可能性就不如上面的例子大。</p><figure><img src="'+A+'" alt="image-20240123203628929" tabindex="0" loading="lazy"><figcaption>image-20240123203628929</figcaption></figure><p>如图6.19所示，为平头顶部形态和平头底部形态的实例。在图示的平头顶部形态中，当第二天的蜡烛线同时完成了一个看跌吞没形态后，平头顶部形态就得到了验证。在平头底部形态1中，包含了一根星线。另外请注意，这个平头底部形态是由相邻的两天形成的，在其形成过程中，市场还对前一周的吞没形态进行了成功的试探。平头底部形态2是由两根锤子线组成的。平头底部形态，加上两个锤子线，两个方面的看涨指标合而为一，揭开了一轮上冲行情的序幕。</p><figure><img src="'+E+'" alt="image-20240123203859120" tabindex="0" loading="lazy"><figcaption>image-20240123203859120</figcaption></figure><p>如图6.20所示，1月24日的低点在0.95美元附近，一周后市场重新向下试探了这一水平。这次试探不仅是成功的，而且同时形成了一个看涨吞没形态。</p><figure><img src="'+q+'" alt="image-20240123204218583" tabindex="0" loading="lazy"><figcaption>image-20240123204218583</figcaption></figure><p>如图6.21所示，在2月14日和15日，市场既形成了一个二日的平头形态，也完成了一个看涨吞没形态。</p><figure><img src="'+v+'" alt="image-20240123204246863" tabindex="0" loading="lazy"><figcaption>image-20240123204246863</figcaption></figure><p>如图6.22所示，在一根长长的白色蜡烛线之后，出现了一根上吊线。这两个星期的最高价处于同样的水平（这种情况甚至包括第三周），于是形成了一个平头顶部形态。在这个平头形态中，两根蜡烛线同时也构成了一个孕线形态。</p><figure><img src="'+D+'" alt="image-20240123204333018" tabindex="0" loading="lazy"><figcaption>image-20240123204333018</figcaption></figure><p>如图6.23所示，6月下旬出现了一个黄昏星形态的变体。在真正的黄昏星形态中，我们希望看到第一根蜡烛线是一根较长的白色蜡烛线。尽管如此，这里还是演变成了一个阻挡区域，下周的上吊线证明了这一阻挡区域的存在。这条上吊线曾经向上达到了前一周的最高点，但功败垂成，于是，形成了一个平头顶部形态。</p><figure><img src="'+V+'" alt="image-20240123204608779" tabindex="0" loading="lazy"><figcaption>image-20240123204608779</figcaption></figure><p>如图6.24所示，为标准普尔指数的周蜡烛线图。在1987年8月的峰处，前面是一根长长的白色蜡烛线，后面跟着一根十字线，形成了一个平头顶部形态。该形态在下一周起到了阻挡作用。在这里，除了平头顶部形态的信号外，还有其它危险信号：<strong>在高价格水平上，一根长长的白色蜡烛线后出现了一根十字线</strong>。第八章我们将详细讨论有关问题。</p><h2 id="捉腰带线" tabindex="-1"><a class="header-anchor" href="#捉腰带线" aria-hidden="true">#</a> 捉腰带线</h2><figure><img src="'+t+'" alt="image-20240123204854080" tabindex="0" loading="lazy"><figcaption>image-20240123204854080</figcaption></figure><p>捉腰带形态是由单独一根蜡烛线构成的，既可能具有看涨的意义，也可能具有看跌的意义。看涨捉腰带形态是一根坚挺的白色蜡烛线；其开市价位于当日的最低点（或者，这根蜡烛线只有极短的下影线），然后市场一路上扬。看涨捉腰带线又称为开盘秃（脚）阳线。如果市场处于低价区域，如图6.25所示，出现了一根长长的看涨捉腰带线，则预示着上冲行情的到来。</p><p>看跌捉腰带形态（如图6.26所示）是一根长长的黑色蜡烛线，它的开市价位于当日的最高点（或者这根蜡烛线只有极短的上影线），然后市场一路下跌。在市场处于高价区的条件下，看跌捉腰带形态的出现，构成了顶部反转信号。看跌捉腰带线有时也称为开盘秃（头）阴线。</p><p><strong>捉腰带蜡烛线的长度愈长，则该形态的技术意义越重大</strong>。**另外，如果捉腰带线是在市场趋势已经发展了较长时间之后才出现的，那么，它的意义也更加重要。**捉腰带形态的日文本名称来自相朴运动的一个术语：羚羊挂角。这个术语的意思是“抓着对手的腰带，将他推出圈外”。<strong>如果市场收市于黑色的看跌捉腰带线之上，则意味着上升趋势已经恢复。如果市场收市于白色的看涨捉腰带线之下，则意味着市场的抛售压力重新积聚起来了。</strong></p><figure><img src="'+j+'" alt="image-20240123210305955" tabindex="0" loading="lazy"><figcaption>image-20240123210305955</figcaption></figure><p>如图6.27所示，看涨捉腰带线1标志着上冲行情的到来。捉腰带线2很有意思。由于这条蜡烛线维持在前一周的低点之上，因此，它不仅与前一周的低点一起构成了一个平头底部形态，同时也验证了这个平头形态的底部信号。随着该形态的完成，市场便开始上涨，直至数周后遇到一个孕线形态，这轮行情才结束。</p><figure><img src="'+N+'" alt="image-20240123210433037" tabindex="0" loading="lazy"><figcaption>image-20240123210433037</figcaption></figure><p>在图6.28中，流星线的出现，是市场遇上麻烦的第一个征兆。流星线的下一天，是一根看跌捉腰带线，它证实了市场顶部的形成。在下一周里，我们又碰到了一根看跌的捉腰带线，这反映出市场潜在的疲弱性质。</p><figure><img src="'+S+'" alt="image-20240123210528121" tabindex="0" loading="lazy"><figcaption>image-20240123210528121</figcaption></figure><p>在如图6.29所示的实例中，2月中旬，两个看跌捉腰带线肩并肩地出现在我们面前。随后，市场发生了一轮短暂而急剧的抛售行情。在这段下跌行情之后，图示的启明星形态构筑了一个市场底部。</p><h2 id="向上跳空两只乌鸦" tabindex="-1"><a class="header-anchor" href="#向上跳空两只乌鸦" aria-hidden="true">#</a> 向上跳空两只乌鸦</h2><figure><img src="'+n+'" alt="image-20240123210630361" tabindex="0" loading="lazy"><figcaption>image-20240123210630361</figcaption></figure><p>如图6.30所示，为向上跳空二只乌鸦形态（瞧，这个名称多拗口）。“向上跳空”指的是图示的小黑色实体与它们之前的实体（即第一个小黑色实体之前的实体，通常是一根长长的白色实体）之间的价格跳空。在图示的形态中，两个黑色的小实体自然就是“两只乌鸦”。两个黑色的小实体好象是栖立在高高的树枝上的两只乌鸦，它们不祥地向下凝视着。从这个形象的比喻来看，显而易见，这是一种看跌的价格形态。在理想的向上跳空两只乌鸦形态中，第二个黑色实体的开市价高于第一个黑色实体的开市价，并且它的收市价低于第一个黑色实体的收市价。</p><p>这个形态在技术上看跌的理论依据大致如下：市场本来处于上升趋势中，并且这一天的开市价同前一天的收市价相比，是向上跳空的，可是市场不能维持这个新高水平，结果当天反而形成了一根黑色蜡烛线。到此时为止，牛方至少还能捞着几根救命稻草，因为这根黑色蜡烛线还能够维持在前一天的收市价之上。第三天的行情又为市场抹上了更深的疲软色彩：当天市场曾经再度创出新高，但是同样未能将这个新高水平维持到收市的时候。而且，更糟糕的是，第三日的收市价低于第二日的收市价。如果市场果真如此坚挺，那么，为什么它不能维持新高水平呢？为什么市场的收市价下降了呢？这时候，牛方心中恐怕正在惴惴不安地盘算着这些问题。思来想去，结论往往是，市场不如自己当初指望的那样坚挺。如果次日（也就是指第四天）市场还是不能拿下前面的制高点，那么，我们可以想见，将会出现更低的价格。</p><p>还有一种与向上跳空二只乌鸦有点瓜葛的蜡烛图形态，其外形与向上跳空二只鸟鸦形态有一定程度的相似之处。但是，与向上跳空二只乌鸦形态不同的是，在上升行情中，这类形态是看涨的。正因为如此，它就成了为数不多的蜡烛图持续形态的一员（其它持续形态我们将在第七章中讨论）。这种形态称为铺垫形态（如图6.31所示）。铺垫形态发生在牛市行情中，是一种看涨的持续形态。在这个形态中，头三根蜡烛线与向上跳空二只乌鸦形态相似，但是此后，又跟了一根黑色蜡烛线。如果接下来的一根蜡烛线是白色的，并向上跳空，向上超过了上述最后一根黑色蜡烛线的上影线；或者这根白色蜡烛线的收市价高于最后一根黑色蜡烛线的最高价，则形成了买入信号。在铺垫形态中，可以有2根、3根乃至4根黑色蜡烛线。相对而言，向上跳空二只乌鸦形态和铺垫形态都是很少见的。</p><figure><img src="'+w+'" alt="image-20240123211253671" tabindex="0" loading="lazy"><figcaption>image-20240123211253671</figcaption></figure><p>如图6.32所示，是一个典型的向上跳空二只乌鸦形态的实例。二月上旬，先是一根长长的白色蜡烛线，后面飞来二只乌鸦。本形态的出现，中止了从一个月之前开始的上涨行情。</p><figure><img src="'+F+'" alt="image-20240123211322439" tabindex="0" loading="lazy"><figcaption>image-20240123211322439</figcaption></figure><p>图6.33所示为铜期货市场。我们可以看到，11月27日，铜市场以一根长长的白色蜡烛线推升了价格水平。在随后的两天中，市场均创出了新高，但都未能维持住。第二天的黑色蜡烛线终于完成了图示的向上跳空二只乌鸦形态。市场由此一路下滑，直到一个十字星线和一个平头底部形态出现才打住。后面这两个形态筑成了下一波上升行情的发射平台。</p><figure><img src="'+G+'" alt="image-20240123211423378" tabindex="0" loading="lazy"><figcaption>image-20240123211423378</figcaption></figure><p>如图6.34所示，是罕见的铺垫形态的一个经典实例。在这个实例中，先是一根坚挺的白色蜡烛线，后面跟着一个向上跳空的黑色蜡烛线。接着，又出现了另外两根小的黑色蜡烛线。这群蜡烛线与最后的那根白色蜡烛线一起，构成了图示的铺垫形态。请注意，本形态同向上跳空二只乌鸦形态其实并没有太大的差别（前面我们曾经交代，在铺垫形态中，也可能仅仅出现两根小的黑色蜡烛线，而不是三根，如此一来，这类形态与向上跳空二只乌鸦形态就更没有什么两样了）。铺垫形态与向上跳空二只乌鸦形态主要的区别在于，在本形态最后，出现了一根白色的蜡烛线，使本形态摇身一变，成为一个看涨形态。根据以上分析，<strong>我向您建议，当向上跳空二只鸟鸦形态出现后，应当在该形态的第二根黑色蜡烛线的最高点上方设置止损保护指令，以防备市场收市于该水平之上。</strong></p><h2 id="三只乌鸦" tabindex="-1"><a class="header-anchor" href="#三只乌鸦" aria-hidden="true">#</a> 三只乌鸦</h2><figure><img src="'+p+'" alt="image-20240123211739156" tabindex="0" loading="lazy"><figcaption>image-20240123211739156</figcaption></figure><p>在向上跳空二只乌鸦形态中，包含了两根黑色蜡烛线。如果在类似的形态中，连续出现了三根依次下降的黑色蜡烛线，则构成了所谓的三只乌鸦形态（图6.35所示）。如果三只乌鸦形态出现在高价格水平上，或者出现在经历了充分发展的上涨行情中，就预示着价格即将下跌。有的时候，三只乌鸦形态又称作三翅乌鸦形态。日本有句俗语：“好事不出门，坏事长翅膀”。拿这句话来形容这种“三只翅膀”的乌鸦，那是再怡当不过了。正如该形态的名称所示，三只乌鸦指的就是这三根黑色的蜡烛线。这三根黑色蜡烛线勾勒出了这么一幅不祥的景象：一群乌鸦栖落在一棵枯朽的大树上。因此，三只乌鸦形态具有看跌的意味。从外形上说，这三根黑色蜡烛线的收市价都应当处于其最低点，或者接近其最低点；毎根黑色蜡烛线的开市价也都应该处于前一个实体的范围之内。另外，分析者可能还希望“三只乌鸦”中的第一根黑色蜡烛线的实体，居于它之前的那根白色蜡烛线的最高点以下。</p><figure><img src="'+H+'" alt="image-20240123211749155" tabindex="0" loading="lazy"><figcaption>image-20240123211749155</figcaption></figure><p>如图6.36所示，是一个典型的三只乌鸦形态的实例。6月中旬，飞来了三只乌鸦。一个月以后，即7月中旬，又出现了另一个三只乌鸦形态。7月的三只乌鸦同时也是市场对6月的三只乌鸦的最高点的试探，这次试探以失败而告终。这个高点的水平大约为33000点。这样，就形成了一个双重顶形态。</p><figure><img src="'+I+'" alt="image-20240123211800325" tabindex="0" loading="lazy"><figcaption>image-20240123211800325</figcaption></figure><p>如图6.37所示，也是一个三只乌鸦形态的实例。6月15日是三只乌鸦中的第一只。这三只乌鸦有个很有意思的地方，第二根黑色蜡烛线和第三根黑色蜡烛线的开市价均分别处在前一根黑色蜡烛线的收市价的水平上，或者与之非常接近。这种情况就称为三只乌鸦接力形态。人们认为这种形态特别疲软，不过，这是一种非常罕见的形态。</p><h2 id="反击线形态-约会线形态" tabindex="-1"><a class="header-anchor" href="#反击线形态-约会线形态" aria-hidden="true">#</a> 反击线形态(约会线形态)</h2><figure><img src="'+s+'" alt="image-20240123212127611" tabindex="0" loading="lazy"><figcaption>image-20240123212127611</figcaption></figure><p><strong>当两根颜色相反的蜡烛线具有相同的收市价时，就形成了一个反击线形态（也称为约会线形态）</strong>。描述这种形态，最好的办法是讨论如图6.38 和图6.39所示的示意图。如图6.38所示，是一个看涨反击蜡烛线的例子。本形态出现在下降行情中。在这个形态中，第一根蜡烛线是一根长长的黑色蜡烛线。在第二根蜡烛线上，市场的开市价急剧地向下跳空。到此刻为止，熊方觉得信心十足。但是马上，牛方发动了反攻，把市场推了上来，使价格重新回到了前一天收市价的水平。于是，先前的下降趋势的马头就被勒住了。</p><p>我们不妨把看涨反击形态同看涨刺透在形态上作一番比较。如果您还记得的话，刺透形态与本图所示的看涨反击线形态一样，也是由两根蜡烛线组成的。它们之间主要的区别是，看涨反击线通常并不把收市价向上推进到前一天的白色实体的内部，而是仅仅回升到前一天的收市价的位置。而在刺透形态中，第二根蜡烛线深深地向上穿入了前一个黑色实体之内。因此，刺透形态与看涨反击线形态相比较，刺透形态是一种更为重要的底部反转信号。尽管如此，正如下面列举的一些实例所显示的，我们对看涨反击线形态还是不可小親的。</p><p>从外形上看，看涨反击线形态与看跌的切入线形态（参见第四章，图4.31）也有相像之处。它们之间的区别是，白色的看涨反击线比切入线形态的白色蜡烛线更长。换句话说，在看涨反击蜡烛线上，市场在开市时急剧地向下跳空然后市场再向上反弹，回升到前一天的收市水平；而在切入蜡烛线上，市场在开市时只是稍稍下跌了一些，然后便回升到前一天的收市水平。</p><p>图6.39所示是一根看跌反击蜡烛线。这种形态属于顶部反转形态，当它出现时，将阻止之前的上涨行情。在这种反击线形态中，第一根蜡烛线是长长的白色蜡烛线。保持了牛市一贯的上升动力。在下一根蜡烛线上，市场在开市时向上跳空。但从此时起，熊方挺身而出，发起反击，将价格拉回到前一天的收市价的水平。如果说看涨反击线形态与刺透形态有渊源的话，那么，看跌反击线形态与乌云盖顶形态也有类似的关系。在看跌反击线形态中，第二天的开市价高于前一天的最高点，这一点与乌云盖顶形态是一致的。但是，与乌云盖顶形态不同的是，这一天的收市价并没有向下穿入前一天的白色蜡烛线之内。由此看来，乌云盖顶形态所发出的顶部反转信号，比看跌反击线形态更强。</p><p><strong>在反击线形态中，一项重要的考虑因素是，第二天的开市价是否强劲地上升到较高的水平（在看跌反击线形态中），或者是否剧烈地下降到较低的水平（在看涨反击线形态中）</strong>。其核心思想是，在该形态第二天开市时，市场本来已经顺着既有趋势向前迈了一大步，但是后来，却发生了意想不到的变故！到当日收市时，市场竟然完全返回到前一天收市价的水平！</p><figure><img src="'+J+'" alt="image-20240123213135915" tabindex="0" loading="lazy"><figcaption>image-20240123213135915</figcaption></figure><p>如图6.40所示，5月29日是一根长的白色蜡烛线。市场本已于一周前开始形成上涨行情，这条蜡烛线就为这段上涨行情增色不少。5月30日，市场在开市时剧烈上涨，充分印证了上述上升趋势。然而，从此往后，市场在当日剩下的交易时间里走的都是下山道。到当日收市时，市场已经完全跌画到前一天收市价的水平。于是，5月29日和30日这两天，就构成了一个看跌反击线形态。</p><figure><img src="'+K+'" alt="image-20240123213213051" tabindex="0" loading="lazy"><figcaption>image-20240123213213051</figcaption></figure><p>如图6.41所示，看跌反击线形态终止了一段上冲行情。</p><figure><img src="'+L+'" alt="image-20240123213235253" tabindex="0" loading="lazy"><figcaption>image-20240123213235253</figcaption></figure><p>如图6.42所示，随着1989年3月的看跌反击线形态的出现，市场一泻而下。几个月以后，，图示的看涨反击线形态撑住了这场暴跌。请记住，对于所有的趋势反转指标来说（比如说反击蜡烛线形态），它们实质上揭示了趋势即将发生变化。这并不意味着价格将掉头转向相反的方向。这里的实例正好说明了这一点。通过这个实例我们看到，图示的底部反转形态发出信号，表明之前的趋势已经结束，于是市场从下跌转为横向延伸。本实例还说明，在反击线形态中，第二根蜡烛线的收市价未必一定与前一天的收市价完全一致，才能够形成有效的反转信号。</p><figure><img src="'+M+'" alt="image-20240123213410723" tabindex="0" loading="lazy"><figcaption>image-20240123213410723</figcaption></figure><p>如图6.43所示，当该流星线出现后，价格逐步受到侵蚀，直到图示的看涨反击线出现，才扭转了颓势。这根看涨反击线还有另一方面的积极性质：当日的开市价本来处在7月底，8月初形成的支撑区的下方，但是，市场并未能坚持住这一新低价位。这也说明，熊方已经丧失了对市场的控制权。</p><h2 id="三山和三川形态" tabindex="-1"><a class="header-anchor" href="#三山和三川形态" aria-hidden="true">#</a> 三山和三川形态</h2><figure><img src="'+r+'" alt="image-20240123213532380" tabindex="0" loading="lazy"><figcaption>image-20240123213532380</figcaption></figure><p>在蜡烛图技术中，还有一些较长期的顶部反转形态和底部反转形态，其中包括三山形态、三川形态、三尊顶部形态、倒三尊底部形态、圆顶形态、平底锅形态（或者说，圆底形态），以及塔形顶部和塔形底部形态。与西方的三重顶形态相仿，日本也有所谓的三山顶部形态<br> （如图6.44所示）。一般认为，本形态构成了一种主要顶部反转过程。如果市场先后三次均从同一个高价位上回落，或者市场对某一个高价位向上进行了三次尝试，但统统归于失败，那么，就形成了一个三山顶部形态。在三山顶部形态的最后一座山的最高点，还应当出现某种看跌的蜡烛图指标（比如说，一根十字线，或者一个乌云盖顶形态等〉，以对三山顶部形态作出确认。</p><p>在三山顶部形态中，如果中间的山峰高于两侧的山峰，则构成了一种特殊的三山形态，称为三尊顶部形态（如图6.45所示）。采用这个名字的原因是，在佛教寺庙的大殿里，中间供奉着释伽牟尼，他的塑像最高大，两边是他的弟子，他们的塑像比较小。这种形态与这群佛像颇为相像。这个形态与头肩形形态对应得非常完美。不过，虽然三尊顶部形态与头肩形是对等的技术信号，但是，日本人应用三尊形态理论的历史，比美国人应用头肩形形态早了100 余年（据我们所知。在美国，最早提及头肩形的是理查德・夏巴克，时间在本世纪30年代。熟悉爱德华和迈吉的经曲著作《股市趋势的技术分析）的朋友都知道，该书的很多材料是以夏巴克的工作为基础的。夏氏是爱徳华的岳父。）有意思的是，西方的市场观察家与东方的技术分析先驱，在这种价格形态上殊途同归了。环绕整个地球，市场心理都是共通的。借用一句日本的格言来形容，“小鸟的叫声，到哪儿都一样。”</p><figure><img src="'+o+'" alt="image-20240123220352263" tabindex="0" loading="lazy"><figcaption>image-20240123220352263</figcaption></figure><p>三川底部形态（如图6.46所示）怡巧是三尊顶部形态的反面。在市场先后三度向下试探某个底部水平后，就形成了这类形态。市场必须向上突破这个底部形态内的最高水平，才能证实底部过程已经完成。与西方的头肩形底部形态（也称为倒头肩形）对等的蜡烛图形态是变体三川底部形态，或者称为倒三尊形态（如图6.47所示）。</p><figure><img src="'+O+'" alt="image-20240123220442399" tabindex="0" loading="lazy"><figcaption>image-20240123220442399</figcaption></figure><p>图6.48是一张难得一见的图例，其中包括了三山顶部形态的各种实际演化过程。下面我们来逐一讨论：</p><p>1.区域1、2、3构成了一个三尊形态，因为中间的山峰在三座山中是最高的。在第三座山的最高处，是一根黄昏星蜡烛线。由这个三山形态引发的抛售行情终止于6月的启明星形态。</p><p>2.市场在A、B.C三处形成了三个山峰。有些日本技术分析师认为，这三座峰是市场向新高水平迈进的三次尝试，就像向上涌起的三阵波涛。第三浪的上涌过程，理当形成一个最高潮（这正是本例的情况）。市场先后三次向上推进到新高水平，三次都未能扩大战果。当第三次上推失败后。牛方终于投降。请注意，第三座山（C）的最高处是一颗黄昏星。</p><p>3.有的日本技术分析师把三山形态理解成市场的三个阶段的上涨过程，也有的把三山形态理解为市场对同一个价格高峰的三次试探。区域C，D，E处组成了一个三山形态，这里的情况符合后一种解释。在区域D，市场通过一个乌云盖项形态发出了顶部信号；在区域E的最高处，市场的顶部信号是一根上吊线，还有紧随其后的一根十字线。</p><figure><img src="'+P+'" alt="image-20240123220830642" tabindex="0" loading="lazy"><figcaption>image-20240123220830642</figcaption></figure><p>在如图6.49所示的三山形态中，在每座山峰处都显示出了看跌的蜡烛图证据。在区域1，有一个看跌吞没形态；在区域2，先是一根上吊线，后面跟着二根十字线；在区域3，又是一个看跌吞没形态。</p><figure><img src="'+Q+'" alt="image-20240123220946804" tabindex="0" loading="lazy"><figcaption>image-20240123220946804</figcaption></figure><p>如图6.50所示，在这个三山形态中，因为中间的山峰是最高的，所以，本形态就成了一个三尊形态。在最高的中间山峰的顶部，有一根黑色实体藏身于前一根白色实体之内，形成了一个孕线形态。</p><figure><img src="'+R+'" alt="image-20240123221012791" tabindex="0" loading="lazy"><figcaption>image-20240123221012791</figcaption></figure><p>如图6.51所示，1988年出现了一个倒三尊形态（即，倒头肩形）。在这个倒三尊形态的三个底部A、B、C处，每个底部都包含一个看涨的蜡烛图信号。在低谷A处，有一根锤子线。在低谷B处，又是一根锤子线，而且这根锤子线还是图示启明星形态的一个组成部分（由该启明星形态引发的上涨行情收场于一个乌云盖顶形态）。在低谷C处，出现了一个斩回蜡烛线形态（它几乎也构成了一个看涨吞没形态）。后来，一旦牛方向上跳空，突破了图示的向下倾斜的阻挡线，市场趋势就转而向上了。日本技术分析师将价格跳空称为窗口（下一章，我们讨论持续形态，还将详细研究窗口的情况）。因为这里用上了价格跣跳空的概念，所以您需要了解，根据日本分析师的看法。价格跳空（即窗口）属于持续性形态。因此，向上跳空是看涨的，向下跳空是看跌的。在本例中，这个向上跳空具备看涨的意味。从1989年第三季度，到1990年第一季度，本图所示的价格活动演变成了一个三尊顶部形态。</p><figure><img src="'+T+'" alt="image-20240123221248277" tabindex="0" loading="lazy"><figcaption>image-20240123221248277</figcaption></figure><p>在三川底部形态中（当然也包括下面这个实例），为了提供买入信号，市场必须以一根白色蜡烛线的形式，收市于本形态的最高点之上（如图6.52所示）。在这个实例中，市场必须向上超越大约102美元的价格水平。请注意102美元的水平如何在3月里的抛售行情中转化为支撑水平的。</p><h2 id="数字3在蜡烛图技术中的重要性" tabindex="-1"><a class="header-anchor" href="#数字3在蜡烛图技术中的重要性" aria-hidden="true">#</a> 数字3在蜡烛图技术中的重要性</h2><p>日本人之所以分外看重三重顶和三重底形态，可能是因为，在日本文化中，数字3具有特殊的意义。作为西方人，我们对三山形态的三个山峰未必有多少特别的感受。在我们的观念中，双重顶形态，乃至更少见的四重顶形态（市场四次向上试探某个高水平），与三重顶形态相比，它们的技术意义是平分秋色、不分伯仲的。但是日本人的想法就不同了。或许，这样一来，他们倒能够为我们揭开西方技术分析理论被我们自己忽略了的一面。有趣的是，在西方技术分析理论中，有许多价格形态和技术概念也是建立在数字3的基础上的，同蜡烛图技术不谋而合。下面一段文字摘自约翰・墨菲的《期货市场技术分析》一书：</p><blockquote><p>有趣的是，“3”这个数字在各种技术分析的理论和应用中都出现得很频繁，而且各有各的门道。说起来，不仅扇形原理用到三条线，而且重要牛市和熊市通常分成三个阶段（参见道氏理论和艾略特波浪理论）；有三种价格跳空；某些较为典型的反转形态，诸如三重顶、头肩形等，均有三个显薯的峰；趋势有三种不同的类型（主要趋势、次要趋势和短暂趋势），以及三种不同方向（上升、下降和横向延伸）；在众所周知的持续性形态中，有三类三角形一-对称三角形、上升三角形和下降三角形；我们的信息主要来源自三个渠道一一价格、交易量以及持仓量。不管到底是什么绦故，反正3这个数字贯穿了技术分析的整个领域，担负着很重要的角色。</p></blockquote><p>约翰・墨菲指的，当然是西方的技术分析理论。不过，他所说的“3这个数字担负着很重要的角色”这句话，用在蜡烛图技术身上尤其准确。过去在日本，“3”这个数字差不多具有某种神秘的渊源。日本有句格言，“好事成三”。这句话正好表达了这样的信念。顺便说一句，虽然日本人把数字3看作幸运的象征，但是数字4却被看作一个不祥的标志。产生这种想法的原因倒是不难弄清楚一在日语中，数字4的发音同“死”字的发音是相同的。下面列举了一些具体的例子，从中您可以看出，3这个数字在蜡烛图技术中出现得非常频繁：有一种称为“白色三兵”的形态预示着上涨行情的到来；不祥的三只乌鸦形态标志着价格的下跌；在顶部形态中，包括三山形态以及三山形态的各种变体；三尊形态；三川底部形态；通过三个窗口（即向上三空形态和向下三空形态，参见第七章〉可以预测一轮行情的运动幅度；上升三法和下降三法（参见第七章）；在三蜡烛线形态中，包括启明星形态和黄昏星形态。日本分析师还认为，如果一个窗口（在上升趋势过程中）没有在三天之内被市场关闭，那么市场将上涨。</p><h2 id="圆形顶部形态和平底锅底部形态-圆形底部形态" tabindex="-1"><a class="header-anchor" href="#圆形顶部形态和平底锅底部形态-圆形底部形态" aria-hidden="true">#</a> 圆形顶部形态和平底锅底部形态(圆形底部形态)</h2><figure><img src="'+c+'" alt="image-20240123222422470" tabindex="0" loading="lazy"><figcaption>image-20240123222422470</figcaption></figure><p>在圆形顶部形态（如图6.53所示）中，市场逐步形成向上凸起的圆弧状图案，在这个过程中，通常出现的是一些较小的实体。最后，当市场向下跳空时，就证明圆形顶部形态巳经完成。这一形态与西方的圆形顶部形态是相同的。<strong>在圆形顶部形态中，应当包含一个向下的窗口，作为市场顶部的验证信号。</strong></p><p>平底锅底部形态（即圆形底部形态，如图6.54所示）反映出市场正处于底部反转过程中，市场逐步呈现出向下凹进的圆弧状图案，然后市场打开一个向上的窗口。本形态的外观与西方的圆形底部形态是一致的，不过，<strong>在日本的平底锅底部形态中，必须出现一个向上的窗口，以证实市场底部的完成。</strong></p><figure><img src="'+U+'" alt="image-20240123222633328" tabindex="0" loading="lazy"><figcaption>image-20240123222633328</figcaption></figure><p>从图6.55 中我们可以看到，随着市场顶部反转形态的形成。逐步显现的圆弧状顶部轮哪，以及其中那群较小的实体，两路线索指明了一个圆形顶形态。请注意在本形态最高处的一根十字线，以及后来的向下打开的窗口，是如何带助我们验证这个圆形顶形态的。在图示的窗口之后，是一根黑色蜡烛线，这是一条捉腰带线，又为我们增添了一条看跌的理由。</p><figure><img src="'+W+'" alt="image-20240123222717769" tabindex="0" loading="lazy"><figcaption>image-20240123222717769</figcaption></figure><p>如图6.56所示，为一个平底锅底部形态，它的底点出现在4月27日和28日，这两天的蜡烛线还组成了一个孕线形态。5月初出现了一个向上打开的窗口，由此证明该平底锅形态终于完成了它的使命。</p><figure><img src="'+X+'" alt="image-20240123222744272" tabindex="0" loading="lazy"><figcaption>image-20240123222744272</figcaption></figure><p>如图6.57所示的平底锅底形态具有一副绝妙的外形。该形态的看涨验证信号来自蜡烛线2。虽然在蜡烛线1和蜡烛线2之间，市场并未形成窗口，但是实际上，蜡烛线1的最高点为1000美元，而蜡烛线2的最低点为997美元。这就意味着，这两根蜡烛线只差4个基本价格单位，就能形成一个窗口。此外，蜡烛线2是一根非常坚挺的白色捉腰带线。</p><h2 id="塔形顶部形态和塔形底部形态" tabindex="-1"><a class="header-anchor" href="#塔形顶部形态和塔形底部形态" aria-hidden="true">#</a> 塔形顶部形态和塔形底部形态</h2><figure><img src="'+m+'" alt="image-20240123222920811" tabindex="0" loading="lazy"><figcaption>image-20240123222920811</figcaption></figure><p>塔形顶部形态属于顶部反转形态。市场本来处在上升趋势中，在某一时刻，出现了一根坚挺的白色蜡烛线（或者出现了一系列高高的白色蜡烛线）。后来，市场先是放缓了上涨的步调，然后，蜡烛线的高点开始下降。最后，市场上出现了一根或者数根长长的黑色蜡烛线，于是，塔形顶部形态就完成了（如图6.58所示）。在本形态中，两侧的长长的蜡烛线形似高塔--因此，它就得了这样的名称。</p><p>塔形底部形态发生在低价格水平上。市场在形成了一根或数根长长的黑色蜡烛线之后，经历了一阵短暂的平静。然后，出现了一根或数根长长的白色蜡烛线。这样就形成了一个塔形底部形态，它两侧的外形也像高塔一般（如图6.59所示）。这就是说，市场先以长长的蜡烛线一路而下，后来又以长长的蜡烛线一路而上。</p><figure><img src="'+Y+'" alt="image-20240123223056510" tabindex="0" loading="lazy"><figcaption>image-20240123223056510</figcaption></figure><p>如图6.60所示，从1982年的第1季度到当年第2季度，市场上出现了一群坚挺的白色蜡烛线，后来，又出现了一系列长长的黑色蜡烛线。于是，高高的白色蜡烛线形成了左边的高塔，而长长的黑色蜡烛线形成了右边的高塔。左侧的三个黑色蜡烛线同时也构成了一个三只乌鸦形态。</p><figure><img src="'+Z+'" alt="image-20240123223145334" tabindex="0" loading="lazy"><figcaption>image-20240123223145334</figcaption></figure><p>在图6.61所示的实例中，显示了两种形态一其中一个是塔形底部形态，另一个是我们未曾讨论过的一种罕见的底部反转形态，称为奇特三川底部形态。首先，我们来看看塔形底部形态。8月28日是一根长长的黑色蜡烛线，然后是一段由小的蜡烛线形成的横向延伸行情，9月7日出现了一根长长的白色蜡烛线，于是这个高塔形底部形态就大功告成了。8月28日的陡直下跌竖起了左侧的高塔，而9月27日的急剧上涨则立起了右侧的高塔。请注意从8月28日到8月30日的三根蜡烛线，我们在图上用1、2、3分别作了标注。这3根蜡烛线组成了一个极其罕见的奇特三川底部形态（如图6.62所示）。</p><figure><img src="'+f+'" alt="image-20240123223643418" tabindex="0" loading="lazy"><figcaption>image-20240123223643418</figcaption></figure><p>在蜡烛图形态中，与这个形态关系最近的是黄昏星形态（疑为笔误，应当是启明星形态--译者）。奇特三川底部形态属于底部反转信号。它的第一根蜡烛线是一根极长的黑色蜡烛线；第二根蜡烛线也是一根黑色实体的蜡烛线，其收市价高于第一根蜡烛线的收市价；第三根蜡烛线是一根具有很小的白色实体的蜡烛线。最后这根蜡烛线说明，市场的抛售压力已经消耗殆尽了。在西方的技术分析术语中，与塔形反转形态最接近的对应形态，要数长钉形形态，或者说V形反转形态。在长钉形反转形态中，市场原先处在强劲的趋势过程中，突然，市场掉转了方向，形成了方向相反的新趋势。塔形顶部形态和塔形底部形态，与圆形顶部形态和平底锅底部形态也有相似的地方。两者最主要的区别是，在塔形形态中，市场反转之前和反转之后，出现的都是长长的实体，而在圆形顶部形态和平底锅底部形态中，则含有窗口。同圆形顶部形态和平底锅底部形态比起来，塔形形态通常含有更多的波动剧烈的蜡烛线。实际上，我们不必担心一个顶部过程到底属于塔形顶部形态，还是属于圆形顶部形态，或者一个底部过程到底属于塔形底部形态，还是属于平底锅形态。一般认为，所有这些形态都是主要反转形态。</p>',141),g2=[a2];function e2(t2,n2){return l(),_("div",null,g2)}const o2=d(i2,[["render",e2],["__file","03-其它反转形态.html.vue"]]);export{o2 as default};
